<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
  }
  h1 { font-size: 1.4rem; margin-bottom: 12px; color: #a8d8ea; letter-spacing: 0.5px; }
  .controls { display: flex; gap: 10px; margin-bottom: 12px; }
  button {
    padding: 8px 18px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
    color: #fff;
    font-weight: 600;
  }
  button:hover { transform: translateY(-1px); filter: brightness(1.2); }
  button:active { transform: translateY(0); }
  #drop { background: #4ecdc4; color: #1a1a2e; }
  #play { background: #ff6b6b; }
  #clear { background: #555; }
  #sim {
    border-radius: 8px;
    box-shadow: 0 0 30px rgba(78, 205, 196, 0.15);
    cursor: crosshair;
    display: block;
  }
</style>
</head>
<body>

<h1>Bouncing Ball Physics Playground</h1>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Play / Pause</button>
  <button id="clear">Clear All</button>
</div>
<canvas id="sim"></canvas>

<script>
(function () {
  'use strict';

  // --- Canvas setup ---
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');

  const W = 500;
  const H = 500;
  canvas.width = W;
  canvas.height = H;

  window.sim = { w: W, h: H };

  // --- State ---
  let balls = [];
  let playing = false;
  let animId = null;

  const GRAVITY = 0.35;
  const RESTITUTION = 0.82;
  const MIN_R = 6, MAX_R = 14;

  // --- Helpers ---
  function rand(min, max) { return Math.random() * (max - min) + min; }

  function colorFor(i) {
    const hslHue = (i * 137.508) % 360;
    return `hsl(${hslHue}, 72%, 62%)`;
  }

  // --- API ---
  window.sim.balls = function () { return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })); };

  window.sim.addBall = function (x, y, vx, vy, r) {
    const ball = {
      x: x || rand(20, W - 20),
      y: y || rand(10, H / 3),
      vx: vx !== undefined ? vx : rand(-4, 4),
      vy: vy !== undefined ? vy : rand(-2, 2),
      r: r !== undefined ? Math.max(MIN_R, Math.min(MAX_R, r)) : rand(MIN_R, MAX_R)
    };
    balls.push(ball);
    draw();
  };

  window.sim.clear = function () {
    balls = [];
    ctx.clearRect(0, 0, W, H);
  };

  // --- Physics step ---
  window.sim.step = function (dt) {
    dt = dt || 1;

    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];

      // Apply gravity
      b.vy += GRAVITY * dt;

      // Integrate position
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // Floor collision (bottom edge)
      if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy *= -RESTITUTION;
      }
      // Ceiling collision (top edge)
      else if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy *= -RESTITUTION;
      }

      // Right wall
      if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx *= -RESTITUTION;
      }
      // Left wall
      else if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx *= -RESTITUTION;
      }

      // Clamp to keep safely inside
      b.x = Math.max(b.r, Math.min(W - b.r, b.x));
      b.y = Math.max(b.r, Math.min(H - b.r, b.y));
    }

    draw();
  };

  // --- Drawing ---
  function draw() {
    ctx.clearRect(0, 0, W, H);

    for (const b of balls) {
      const grad = ctx.createRadialGradient(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.15, b.x, b.y, b.r);
      grad.addColorStop(0, '#fff');
      grad.addColorStop(0.2, colorFor(balls.indexOf(b)));
      grad.addColorStop(1, shadeColor(colorFor(balls.indexOf(b)), -40));

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();

      // Subtle outline
      ctx.strokeStyle = 'rgba(255,255,255,0.18)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }
  }

  function shadeColor(hex, percent) {
    const num = parseInt(hex.replace('#', ''), 16);
    const amt = Math.round(2.55 * percent);
    const R = Math.max(0, Math.min(255, (num >> 16) + amt));
    const G = Math.max(0, Math.min(255, ((num >> 8) & 0x00FF) + amt));
    const B = Math.max(0, Math.min(255, (num & 0x0000FF) + amt));
    return `rgb(${R},${G},${B})`;
  }

  // --- Animation loop ---
  function tick() {
    if (!playing) return;
    window.sim.step();
    animId = requestAnimationFrame(tick);
  }

  function startLoop() {
    if (animId !== null && playing) return;
    if (balls.length === 0) return;
    playing = true;
    tick();
  }

  function stopLoop() {
    playing = false;
    cancelAnimationFrame(animId);
    animId = null;
  }

  // --- Event listeners ---
  document.getElementById('drop').addEventListener('click', () => {
    window.sim.addBall(undefined, undefined, rand(-3, 3), rand(-2, 2));
  });

  document.getElementById('play').addEventListener('click', () => {
    if (playing) stopLoop(); else startLoop();
  });

  document.getElementById('clear').addEventListener('click', window.sim.clear);

  canvas.addEventListener('click', function (e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    window.sim.addBall(x, y);
  });

  // --- Initial draw ---
  draw();
})();
</script>
</body>
</html>
